package com.example.rbacexample;

import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;

@SpringBootApplication
public class RbacExampleApplication {
    public static void main(String[] args) {
        SpringApplication.run(RbacExampleApplication.class, args);
    }
}

package com.example.rbacexample.model;

public class Role {
    private String name;

    public Role(String name) {
        this.name = name;
    }

    // getters and setters
}

package com.example.rbacexample.model;

public class Permission {
    private String name;

    public Permission(String name) {
        this.name = name;
    }

    // getters and setters
}

package com.example.rbacexample.model;

import java.util.Set;

public class User {
    private String username;
    private Set<Role> roles;

    public User(String username, Set<Role> roles) {
        this.username = username;
        this.roles = roles;
    }

    // getters and setters
}

package com.example.rbacexample.service;

import com.example.rbacexample.model.Role;
import com.example.rbacexample.model.Permission;
import com.example.rbacexample.model.User;

import java.util.HashSet;
import java.util.Set;

public class RbacService {
    public boolean hasPermission(User user, Permission permission) {
        for (Role role : user.getRoles()) {
            if (role.getPermissions().contains(permission)) {
                return true;
            }
        }
        return false;
    }
}
